kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelMaskedCumsumCustom {
public:
    __aicore__ inline KernelMaskedCumsumCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR mask, GM_ADDR y,
                                uint32_t totalLength, uint32_t rowLength,
                                uint32_t tileLength, uint32_t blockDim, int32_t dim)
    {
        totalLen_ = totalLength;
        rowLen_ = rowLength;
        tileLen_ = tileLength;
        blockDim_ = blockDim;
        dim_ = dim;
        numRows_ = (rowLen_ == 0) ? 1 : (totalLen_ / rowLen_);

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        maskGm_.SetGlobalBuffer((__gm__ bool*)mask, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        // Allocate local buffers for one tile
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueMask_, BUFFER_NUM, tileLen_ * sizeof(bool));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || rowLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        uint32_t rowIdx = blockIdx;
        while (rowIdx < numRows_) {
            ProcessRow(rowIdx);
            rowIdx += blockNum;
        }
    }

private:
    __aicore__ inline void ProcessRow(uint32_t rowIdx)
    {
        uint32_t rowOffset = rowIdx * rowLen_;
        float state = 0.0f;
        uint32_t remaining = rowLen_;

        // Process row in tiles
        for (uint32_t tileOffset = 0; tileOffset < rowLen_; tileOffset += tileLen_) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;

            // Copy x tile
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[rowOffset + tileOffset], curLen);
            inQueueX_.EnQue(xLocal);

            // Copy mask tile
            AscendC::LocalTensor<bool> maskLocal = inQueueMask_.AllocTensor<bool>();
            AscendC::DataCopy(maskLocal, maskGm_[rowOffset + tileOffset], curLen);
            inQueueMask_.EnQue(maskLocal);

            // Dequeue
            xLocal = inQueueX_.DeQue<float>();
            maskLocal = inQueueMask_.DeQue<bool>();

            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

            // Compute masked cumulative sum for this tile
            for (uint32_t i = 0; i < curLen; ++i) {
                bool m = maskLocal(i);
                float xv = xLocal(i);
                if (m) {
                    state += xv;
                }
                yLocal(i) = state;
            }

            outQueueY_.EnQue(yLocal);
            yLocal = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[rowOffset + tileOffset], yLocal, curLen);

            outQueueY_.FreeTensor(yLocal);
            inQueueX_.FreeTensor(xLocal);
            inQueueMask_.FreeTensor(maskLocal);

            remaining -= curLen;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueMask_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<bool> maskGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t rowLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t blockDim_ {0};
    int32_t dim_ {-1};
    uint32_t numRows_ {0};
};

extern "C" __global__ __aicore__ void masked_cumsum_custom(GM_ADDR x, GM_ADDR mask, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelMaskedCumsumCustom op;
    op.Init(x, mask, y, tiling_data.totalLength, tiling_data.rowLength, tiling_data.tileLength, tiling_data.blockDim, tiling_data.dim);
    op.Process();
}
